import { GoogleGenerativeAI } from "@google/generative-ai";
import { NextResponse } from "next/server";

// SDK'yı API anahtarı ile başlat
const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY as string);

export async function POST(request: Request) {
    try {
        const body = await request.json();
        const { prompt } = body;

        if (!prompt) {
            return NextResponse.json({ error: "Prompt eksik" }, { status: 400 });
        }

        // Gemini 1.5 pro modelini kullan (hızlı ve genel amaçlı)
        const model = genAI.getGenerativeModel({ model: "gemini-pro" });

        // Modeli çağır ve yanıtı al
        const result = await model.generateContent(prompt);
        const responseText = result.response.text();

        return NextResponse.json({ text: responseText });

    } catch (error) {
        console.error("Gemini API Hatası:", error);
        return NextResponse.json({ error: "İç sunucu hatası" }, { status: 500 });
    }
}